dec_med = pow (0.9, 30/fps);;
dec_slow = pow (0.99, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (.5+avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %16;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = bass + mid + treb;;
k1 =  is_beat*((index) == (0));;
p1 =  k1*(p1+1) + (1-k1)*p1;;
p2 = dec_slow * p2+ (1-dec_slow)*p1;;
rott = p2 * 3.1416/4;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
q5 = index/12-.5;;
q6 = sin (time/21);;
q7 = 6 + 10 * (1+sin (time/7));;
q32 = pow(0.98, 30/fps); //fade;
